import React, { useState } from "react";
import { useForm, ValidationError } from "@formspree/react";

function Contact() {
  const [state, handleSubmit] = useForm("xwvnjkgl"); // your Formspree ID
  const [formValues, setFormValues] = useState({ name: "", email: "", message: "" });

  const handleChange = (e) => {
    setFormValues({ ...formValues, [e.target.name]: e.target.value });
  };

  const handleReset = () => {
    setFormValues({ name: "", email: "", message: "" });
  };

  if (state.succeeded) {
    return (
      <div style={{
        backgroundColor: "#d4edda",
        color: "#155724",
        padding: "15px",
        borderRadius: "8px",
        border: "1px solid #c3e6cb",
        margin: "20px auto",
        maxWidth: "500px",
        textAlign: "center",
        fontWeight: "bold"
      }}>
        ✅ Thank you! Your message has been sent successfully.
      </div>
    );
  }

  return (
    <div style={{ padding: "20px" }}>
      <h2>Contact Us</h2>
      <p><strong>Office:</strong> 5 Elephant Close, Borrowdale West, Harare</p>
      <p><strong>Phone:</strong> +263 785 002 561</p>
      <p><strong>Email:</strong> pnovontony@yahoo.com</p>

      {state.errors && state.errors.length > 0 && (
        <div style={{
          backgroundColor: "#f8d7da",
          color: "#721c24",
          padding: "15px",
          borderRadius: "8px",
          border: "1px solid #f5c6cb",
          margin: "20px auto",
          maxWidth: "500px",
          textAlign: "center",
          fontWeight: "bold"
        }}>
          ❌ Something went wrong. Please check your details and try again.
        </div>
      )}

      <form onSubmit={handleSubmit} style={{ marginTop: "20px" }}>
        <div style={{ marginBottom: "10px" }}>
          <label>Name:</label><br />
          <input
            type="text"
            name="name"
            value={formValues.name}
            onChange={handleChange}
            required
            style={{ width: "100%", padding: "8px" }}
          />
        </div>
        <div style={{ marginBottom: "10px" }}>
          <label>Email:</label><br />
          <input
            type="email"
            name="email"
            value={formValues.email}
            onChange={handleChange}
            required
            style={{ width: "100%", padding: "8px" }}
          />
          <ValidationError prefix="Email" field="email" errors={state.errors} />
        </div>
        <div style={{ marginBottom: "10px" }}>
          <label>Message:</label><br />
          <textarea
            name="message"
            value={formValues.message}
            onChange={handleChange}
            required
            rows="4"
            style={{ width: "100%", padding: "8px" }}
          />
          <ValidationError prefix="Message" field="message" errors={state.errors} />
        </div>
        <button type="submit" disabled={state.submitting} style={{ padding: "10px 20px", marginRight: "10px" }}>
          {state.submitting ? "Sending…" : "Send Message"}
        </button>
        <button type="button" onClick={handleReset} style={{ padding: "10px 20px", backgroundColor: "#eee" }}>
          Reset
        </button>
      </form>
    </div>
  );
}

export default Contact;
